#include <imgui.h>
#include <backends/imgui_impl_sdl3.h>
#include <backends/imgui_impl_vulkan.h>
#include <SDL3/SDL.h>
#include <vulkan/vulkan.h>

struct GuiContext {
    SDL_Window* window;
    VkInstance instance;
    VkPhysicalDevice physical_device;
    VkDevice device;
    uint32_t queue_family;
    VkQueue queue;
    VkRenderPass render_pass;
    uint32_t image_count;
    VkDescriptorPool descriptor_pool;
};

void InitGui(GuiContext& ctx) {
    IMGUI_CHECKVERSION();
    ImGui::CreateContext();
    ImGui::GetIO().ConfigFlags |= ImGuiConfigFlags_DockingEnable;

    ImGui_ImplSDL3_InitForVulkan(ctx.window);

    ImGui_ImplVulkan_InitInfo init_info = {};
    init_info.Instance = ctx.instance;
    init_info.PhysicalDevice = ctx.physical_device;
    init_info.Device = ctx.device;
    init_info.QueueFamily = ctx.queue_family;
    init_info.Queue = ctx.queue;
    init_info.DescriptorPool = ctx.descriptor_pool;
    init_info.MinImageCount = ctx.image_count;
    init_info.ImageCount = ctx.image_count;
    init_info.MSAASamples = VK_SAMPLE_COUNT_1_BIT;
    ImGui_ImplVulkan_Init(&init_info, ctx.render_pass);
}

void RunGuiFrame(VkCommandBuffer command_buffer) {
    ImGui_ImplVulkan_NewFrame();
    ImGui_ImplSDL3_NewFrame();
    ImGui::NewFrame();

    static bool show_stats = true;
    ImGui::Begin("Renderer Debug");
    ImGui::Text("SDL3 drives events, Vulkan draws the UI.");
    ImGui::Checkbox("Show Stats", &show_stats);
    ImGui::End();

    ImGui::Render();
    ImGui_ImplVulkan_RenderDrawData(ImGui::GetDrawData(), command_buffer);
}

void HandleGuiEvent(const SDL_Event& event) {
    ImGui_ImplSDL3_ProcessEvent(&event);
}

void ShutdownGui() {
    ImGui_ImplVulkan_Shutdown();
    ImGui_ImplSDL3_Shutdown();
    ImGui::DestroyContext();
}

